import React from 'react';

const ResizeHandle = ({ onMouseDown, isVertical = true, isActive = false, side = 'right' }) => {
  const handleMouseDown = (e) => {
    onMouseDown(e, side);
  };

  return (
    <div
      className={`resize-handle ${isVertical ? 'resize-handle--vertical' : 'resize-handle--horizontal'} ${isActive ? 'resize-handle--active' : ''} resize-${side}`}
      onMouseDown={handleMouseDown}
    >
      <div className="resize-handle__indicator">
        <div className="resize-handle__dots">
          <span></span>
          <span></span>
          <span></span>
        </div>
      </div>
      {isVertical && (
        <div className="resize-handle__dual-indicator">
          <span className="resize-handle__arrow resize-handle__arrow--left">{'<'}</span>
          <span className="resize-handle__arrow resize-handle__arrow--right">{'>'}</span>
        </div>
      )}
    </div>
  );
};

export default ResizeHandle;
